"use client"

import { useState } from "react"
import { useAuth } from "@/context/AuthContext"
import { redirect } from "next/navigation"
import { Card, CardContent, CardDescription, CardHeader, CardTitle } from "@/components/ui/card"
import { Button } from "@/components/ui/button"
import { Alert, AlertDescription, AlertTitle } from "@/components/ui/alert"
import { Badge } from "@/components/ui/badge"
import { Database, CheckCircle, XCircle, Loader2, AlertTriangle, ArrowLeft } from "lucide-react"
import Link from "next/link"
import { DB_PROVIDER, initializeDatabase, type InitResult } from "@/lib/db"

export default function InitDatabasePage() {
  const { user, loading: authLoading } = useAuth()
  const [initStatus, setInitStatus] = useState<InitResult | null>(null)
  const [isInitializing, setIsInitializing] = useState(false)

  // Redirect non-authenticated users
  if (!authLoading && !user) {
    redirect("/auth/signin")
  }

  // Check if user is admin (you can customize this based on your auth setup)
  const isAdmin = user?.role === "admin" || user?.email?.endsWith("@vitamend.org")

  if (!authLoading && !isAdmin) {
    redirect("/dashboard")
  }

  const handleInitialize = async () => {
    setIsInitializing(true)
    setInitStatus(null)

    try {
      const result = await initializeDatabase()
      setInitStatus(result)
    } catch (error: any) {
      setInitStatus({
        success: false,
        message: error.message || "An unexpected error occurred",
      })
    } finally {
      setIsInitializing(false)
    }
  }

  if (authLoading) {
    return (
      <div className="flex items-center justify-center min-h-screen">
        <div className="text-center">
          <Loader2 className="h-8 w-8 animate-spin mx-auto text-primary" />
          <p className="mt-4 text-muted-foreground">Loading...</p>
        </div>
      </div>
    )
  }

  return (
    <div className="container mx-auto px-4 py-8 max-w-2xl">
      <Link href="/admin" className="inline-flex items-center text-sm text-muted-foreground hover:text-foreground mb-6">
        <ArrowLeft className="h-4 w-4 mr-2" />
        Back to Admin Dashboard
      </Link>

      <Card>
        <CardHeader>
          <div className="flex items-center gap-3">
            <div className="p-2 bg-primary/10 rounded-lg">
              <Database className="h-6 w-6 text-primary" />
            </div>
            <div>
              <CardTitle>Database Initialization</CardTitle>
              <CardDescription>Initialize the database schema for VitaMend</CardDescription>
            </div>
          </div>
        </CardHeader>
        <CardContent className="space-y-6">
          {/* Current Provider Info */}
          <div className="flex items-center justify-between p-4 bg-muted/50 rounded-lg">
            <div>
              <p className="text-sm font-medium">Active Database Provider</p>
              <p className="text-xs text-muted-foreground">Set via NEXT_PUBLIC_DB_PROVIDER environment variable</p>
            </div>
            <Badge variant="secondary" className="text-sm">
              {DB_PROVIDER.toUpperCase()}
            </Badge>
          </div>

          {/* Provider-specific instructions */}
          <div className="text-sm text-muted-foreground space-y-2">
            <p className="font-medium text-foreground">What this will do:</p>
            <ul className="list-disc list-inside space-y-1 ml-2">
              {DB_PROVIDER === "supabase" && (
                <>
                  <li>Create profiles, donations, medicines, and volunteers tables</li>
                  <li>Set up Row Level Security (RLS) policies</li>
                  <li>Create necessary indexes for performance</li>
                </>
              )}
              {DB_PROVIDER === "firebase" && (
                <>
                  <li>Initialize Firestore collections</li>
                  <li>Create a _meta/initialized document to track state</li>
                </>
              )}
              {DB_PROVIDER === "mongodb" && (
                <>
                  <li>Create collections with proper indexes</li>
                  <li>Set up validation schemas</li>
                </>
              )}
              {DB_PROVIDER === "mysql" && (
                <>
                  <li>Create tables with IF NOT EXISTS</li>
                  <li>Set up indexes and foreign keys</li>
                </>
              )}
              {DB_PROVIDER === "mock" && (
                <>
                  <li>Initialize in-memory storage</li>
                  <li>Add sample medicines data for testing</li>
                </>
              )}
            </ul>
          </div>

          {/* Status Alert */}
          {initStatus && (
            <Alert variant={initStatus.success ? "default" : "destructive"}>
              {initStatus.success ? (
                initStatus.alreadyInitialized ? (
                  <AlertTriangle className="h-4 w-4" />
                ) : (
                  <CheckCircle className="h-4 w-4" />
                )
              ) : (
                <XCircle className="h-4 w-4" />
              )}
              <AlertTitle>
                {initStatus.success ? (initStatus.alreadyInitialized ? "Already Initialized" : "Success") : "Error"}
              </AlertTitle>
              <AlertDescription>{initStatus.message}</AlertDescription>
            </Alert>
          )}

          {/* Initialize Button */}
          <Button onClick={handleInitialize} disabled={isInitializing} className="w-full" size="lg">
            {isInitializing ? (
              <>
                <Loader2 className="h-4 w-4 mr-2 animate-spin" />
                Initializing Database...
              </>
            ) : (
              <>
                <Database className="h-4 w-4 mr-2" />
                Initialize Database
              </>
            )}
          </Button>

          {/* Safety Note */}
          <p className="text-xs text-muted-foreground text-center">
            This operation is idempotent and safe to run multiple times. It will not delete existing data.
          </p>
        </CardContent>
      </Card>
    </div>
  )
}

import { type NextRequest, NextResponse } from "next/server"
import { put } from "@vercel/blob"

export const runtime = "nodejs"
export const dynamic = "force-dynamic"
export const revalidate = 0

export async function POST(request: NextRequest) {
  try {
    const formData = await request.formData()
    const file = formData.get("file") as File

    if (!file) {
      return NextResponse.json({ success: false, error: "No file provided" }, { status: 400 })
    }

    if (file.size > 10 * 1024 * 1024) {
      return NextResponse.json({ success: false, error: "File too large (max 10MB)" }, { status: 400 })
    }

    const blob = await put(file.name, file, {
      access: "public",
    })

    return NextResponse.json({
      success: true,
      url: blob.url,
      name: blob.pathname,
    })
  } catch (error: any) {
    console.error("Upload error:", error)
    return NextResponse.json({ success: false, error: error.message || "Failed to upload file" }, { status: 500 })
  }
}

"use client"

import type React from "react"
import { useState, useEffect } from "react"
import { useRouter } from "next/navigation"
import { Button } from "@/components/ui/button"
import { Card, CardContent, CardHeader, CardTitle } from "@/components/ui/card"
import { Input } from "@/components/ui/input"
import { Label } from "@/components/ui/label"
import { useToast } from "@/components/ui/use-toast"
import { useAuth } from "@/context/AuthContext"
import Link from "next/link"
import Image from "next/image"

export default function SignIn() {
  const [email, setEmail] = useState("")
  const [password, setPassword] = useState("")
  const [showPassword, setShowPassword] = useState(false)
  const [mounted, setMounted] = useState(false)
  const [isLoading, setIsLoading] = useState(false)
  const router = useRouter()
  const { toast } = useToast()
  const { user, signIn } = useAuth()

  useEffect(() => {
    setMounted(true)
  }, [])

  useEffect(() => {
    if (user || (typeof window !== 'undefined' && localStorage.getItem("token"))) {
      router.push("/dashboard")
    }
  }, [user, router])

  const handleSubmit = async (e: React.FormEvent) => {
    e.preventDefault()
    setIsLoading(true)

    try {
      await signIn(email, password)
      toast({
        title: "Success",
        description: "Signed in successfully",
      })
      router.push("/dashboard")
    } catch (error: any) {
      toast({
        title: "Error",
        description: error.message || "Invalid credentials",
        variant: "destructive",
      })
    } finally {
      setIsLoading(false)
    }
  }

  if (!mounted) return null

  return (
    <div className="min-h-screen bg-gradient-to-br from-blue-50 to-purple-50 dark:bg-black flex items-center justify-center p-4 pt-24">
      <Card className="w-full max-w-md transition-all duration-300 hover:shadow-lg rounded-3xl border border-white shadow-xl bg-white/80 backdrop-blur-md">
        <CardHeader>
          <CardTitle className="text-2xl text-center flex flex-col items-center justify-center gap-4">
            <Image
              src="/logo.png"
              alt="VitaMend Logo"
              width={120}
              height={120}
              className="drop-shadow-md"
            />
            <span className="font-bold text-slate-800 text-3xl">Sign In</span>
          </CardTitle>
        </CardHeader>
        <CardContent className="space-y-4 px-8 pb-8">
          <form onSubmit={handleSubmit} className="space-y-6">
            <div className="space-y-2">
              <Label htmlFor="email" className="text-gray-600 font-semibold">Email</Label>
              <Input
                id="email"
                type="email"
                value={email}
                onChange={(e) => setEmail(e.target.value)}
                required
                className="transition-all py-6 duration-200 focus:ring-2 focus:ring-blue-500/20 rounded-xl"
              />
            </div>
            <div className="space-y-2">
              <Label htmlFor="password" className="text-gray-600 font-semibold">Password</Label>
              <div className="relative">
                <Input
                  id="password"
                  type={showPassword ? "text" : "password"}
                  value={password}
                  onChange={(e) => setPassword(e.target.value)}
                  required
                  className="transition-all py-6 duration-200 focus:ring-2 focus:ring-blue-500/20 rounded-xl pr-12"
                />
                <button
                  type="button"
                  onClick={() => setShowPassword(!showPassword)}
                  className="absolute right-3 top-1/2 -translate-y-1/2 text-sm text-gray-500 hover:text-gray-700 transition-colors font-medium"
                >
                  {showPassword ? "Hide" : "Show"}
                </button>
              </div>
            </div>
            <Button
              type="submit"
              className="w-full bg-blue-600 hover:bg-blue-700 transition-all duration-200 rounded-2xl py-7 text-lg font-bold shadow-lg shadow-blue-500/30"
              disabled={isLoading}
            >
              {isLoading ? "Signing in..." : "Sign In"}
            </Button>
          </form>

          <p className="text-center text-sm text-gray-500 mt-8">
            {"Don't have an account? "}
            <Link href="/auth/signup" className="text-blue-600 font-bold hover:underline transition-colors">
              Sign up
            </Link>
          </p>
        </CardContent>
      </Card>
    </div>
  )
}

"use client"

import type React from "react"
import { useState, useEffect } from "react"
import { useRouter } from "next/navigation"
import { Button } from "@/components/ui/button"
import { Card, CardContent, CardHeader, CardTitle } from "@/components/ui/card"
import { Input } from "@/components/ui/input"
import { Label } from "@/components/ui/label"
import { Select, SelectContent, SelectItem, SelectTrigger, SelectValue } from "@/components/ui/select"
import { useToast } from "@/components/ui/use-toast"
import { useAuth } from "@/context/AuthContext"
import Link from "next/link"
import Image from "next/image"

export default function SignUp() {
  const [formData, setFormData] = useState({
    name: "",
    email: "",
    password: "",
    confirmPassword: "",
    role: "donor",
  })
  const [showPassword, setShowPassword] = useState(false)
  const [showConfirmPassword, setShowConfirmPassword] = useState(false)
  const [mounted, setMounted] = useState(false)
  const [isLoading, setIsLoading] = useState(false)
  const router = useRouter()
  const { toast } = useToast()
  const { signUp } = useAuth()

  useEffect(() => {
    setMounted(true)
  }, [])

  const handleSubmit = async (e: React.FormEvent) => {
    e.preventDefault()

    if (formData.password !== formData.confirmPassword) {
      toast({
        title: "Error",
        description: "Passwords do not match",
        variant: "destructive",
      })
      return
    }

    if (formData.password.length < 6) {
      toast({
        title: "Error",
        description: "Password must be at least 6 characters",
        variant: "destructive",
      })
      return
    }

    setIsLoading(true)

    try {
      await signUp(formData.email, formData.password, formData.name, formData.role)
      toast({
        title: "Success",
        description: "Account created successfully!",
      })
      router.push("/dashboard")
    } catch (error: any) {
      toast({
        title: "Error",
        description: error.message || "Failed to create account",
        variant: "destructive",
      })
    } finally {
      setIsLoading(false)
    }
  }

  if (!mounted) return null

  return (
    <div className="min-h-screen bg-gradient-to-b from-background to-muted/30 dark:bg-black flex items-center justify-center p-4">
      <Card className="w-full max-w-md transition-all duration-300 hover:shadow-lg">
        <CardHeader>
          <CardTitle className="text-2xl text-center text-primary flex flex-col items-center justify-center gap-3">
            <Image
              src="/logo.png"
              alt="VitaMend Logo"
              width={120}
              height={120}
              className="rounded-lg"
            />
            <span>Join VitaMend</span>
            <span className="text-sm font-serif text-emerald-600 dark:text-emerald-400 font-normal italic">
              सर्वे सन्तु निरामयाः
            </span>
          </CardTitle>
        </CardHeader>
        <CardContent>
          <form onSubmit={handleSubmit} className="space-y-4">
            <div className="space-y-2">
              <Label htmlFor="name">Full Name</Label>
              <Input
                id="name"
                value={formData.name}
                onChange={(e) => setFormData({ ...formData, name: e.target.value })}
                required
                className="transition-all duration-200 focus:ring-2 focus:ring-emerald-500/20"
              />
            </div>
            <div className="space-y-2">
              <Label htmlFor="email">Email</Label>
              <Input
                id="email"
                type="email"
                value={formData.email}
                onChange={(e) => setFormData({ ...formData, email: e.target.value })}
                required
                className="transition-all duration-200 focus:ring-2 focus:ring-emerald-500/20"
              />
            </div>
            <div className="space-y-2">
              <Label htmlFor="role">I want to</Label>
              <Select value={formData.role} onValueChange={(value) => setFormData({ ...formData, role: value })}>
                <SelectTrigger className="transition-all duration-200">
                  <SelectValue />
                </SelectTrigger>
                <SelectContent>
                  <SelectItem value="donor">Donate Medicines</SelectItem>
                  <SelectItem value="volunteer">Volunteer</SelectItem>
                </SelectContent>
              </Select>
            </div>
            <div className="space-y-2">
              <Label htmlFor="password">Password</Label>
              <div className="relative">
                <Input
                  id="password"
                  type={showPassword ? "text" : "password"}
                  value={formData.password}
                  onChange={(e) => setFormData({ ...formData, password: e.target.value })}
                  required
                  className="transition-all duration-200 focus:ring-2 focus:ring-emerald-500/20 pr-12"
                />
                <button
                  type="button"
                  onClick={() => setShowPassword(!showPassword)}
                  className="absolute right-3 top-1/2 -translate-y-1/2 text-sm text-gray-500 hover:text-gray-700 transition-colors font-medium"
                >
                  {showPassword ? "Hide" : "Show"}
                </button>
              </div>
            </div>
            <div className="space-y-2">
              <Label htmlFor="confirmPassword">Confirm Password</Label>
              <div className="relative">
                <Input
                  id="confirmPassword"
                  type={showConfirmPassword ? "text" : "password"}
                  value={formData.confirmPassword}
                  onChange={(e) => setFormData({ ...formData, confirmPassword: e.target.value })}
                  required
                  className="transition-all duration-200 focus:ring-2 focus:ring-emerald-500/20 pr-12"
                />
                <button
                  type="button"
                  onClick={() => setShowConfirmPassword(!showConfirmPassword)}
                  className="absolute right-3 top-1/2 -translate-y-1/2 text-sm text-gray-500 hover:text-gray-700 transition-colors font-medium"
                >
                  {showConfirmPassword ? "Hide" : "Show"}
                </button>
              </div>
            </div>
            <Button
              type="submit"
              className="w-full bg-emerald-600 hover:bg-emerald-700 transition-all duration-200"
              disabled={isLoading}
            >
              {isLoading ? "Creating account..." : "Create Account"}
            </Button>
          </form>

          <p className="text-center text-sm text-muted-foreground mt-4">
            Already have an account?{" "}
            <Link href="/auth/signin" className="text-emerald-600 hover:underline transition-colors">
              Sign in
            </Link>
          </p>
        </CardContent>
      </Card>
    </div>
  )
}

"use client"

import type React from "react"
import { useState, useEffect } from "react"
import { Button } from "@/components/ui/button"
import { Card, CardContent, CardDescription, CardHeader, CardTitle } from "@/components/ui/card"
import { Input } from "@/components/ui/input"
import { Label } from "@/components/ui/label"
import { Textarea } from "@/components/ui/textarea"
import { useToast } from "@/components/ui/use-toast"
import { Loader2, Upload, X, Sparkles, Heart } from "lucide-react"
import { OCRService } from "@/lib/ai/ocr-service"
import { getDb, type DatabaseAdapter } from "@/lib/db"

export default function DonationForm() {
  const [isSubmitting, setIsSubmitting] = useState(false)
  const [isProcessingOCR, setIsProcessingOCR] = useState(false)
  const [images, setImages] = useState<File[]>([])
  const [db, setDb] = useState<DatabaseAdapter | null>(null)
  const { toast } = useToast()

  const [formData, setFormData] = useState({
    medicineName: "",
    brand: "",
    genericName: "",
    dosage: "",
    quantity: "",
    expiryDate: "",
    condition: "unopened",
    category: "tablet",
    donorName: "",
    donorEmail: "",
    donorPhone: "",
    donorAddress: "",
    notes: "",
  })

  useEffect(() => {
    getDb().then(setDb)
  }, [])

  const handleInputChange = (e: React.ChangeEvent<HTMLInputElement | HTMLTextAreaElement | HTMLSelectElement>) => {
    const { name, value } = e.target
    setFormData((prev) => ({ ...prev, [name]: value }))
  }

  const handleImageUpload = async (e: React.ChangeEvent<HTMLInputElement>) => {
    const files = Array.from(e.target.files || [])
    if (files.length + images.length > 5) {
      toast({
        title: "Too many images",
        description: "You can upload a maximum of 5 images",
        variant: "destructive",
      })
      return
    }

    setImages((prev) => [...prev, ...files])

    if (files.length > 0 && !formData.medicineName) {
      await processImageWithOCR(files[0])
    }
  }

  const preprocessImage = (file: File): Promise<string> => {
    return new Promise((resolve) => {
      const reader = new FileReader();
      reader.onload = (e) => {
        const img = new Image();
        img.onload = () => {
          const canvas = document.createElement("canvas");
          const ctx = canvas.getContext("2d");
          if (!ctx) {
            resolve(URL.createObjectURL(file));
            return;
          }

          canvas.width = img.width;
          canvas.height = img.height;

          // Apply contrast and brightness filters
          ctx.filter = "contrast(200%) brightness(150%)";
          ctx.drawImage(img, 0, 0);

          resolve(canvas.toDataURL("image/jpeg", 0.9));
        };
        img.src = e.target?.result as string;
      };
      reader.readAsDataURL(file);
    });
  }

  const processImageWithOCR = async (file: File) => {
    setIsProcessingOCR(true)

    try {
      const imageUrl = await preprocessImage(file);

      toast({
        title: "AI Processing Image",
        description: "Extracting medicine information...",
      })

      const [validation, expiryDate, medicineNames] = await Promise.all([
        OCRService.validateMedicineImage(imageUrl),
        OCRService.extractExpiryDate(imageUrl),
        OCRService.extractMedicineName(imageUrl),
      ])

      if (medicineNames.length > 0 && !formData.medicineName) {
        setFormData((prev) => ({ ...prev, medicineName: medicineNames[0] }))
      }

      if (expiryDate && !formData.expiryDate) {
        const formattedDate = expiryDate.toISOString().split("T")[0]
        setFormData((prev) => ({ ...prev, expiryDate: formattedDate }))
      }

      if (validation.isValid) {
        toast({
          title: "Medicine Verified",
          description: `AI confidence: ${Math.round(validation.confidence)}%`,
        })
      } else {
        toast({
          title: "Verification Issues",
          description: validation.issues.join(", "),
          variant: "destructive",
        })
      }
    } catch (error) {
      console.error("OCR error:", error)
      toast({
        title: "OCR Processing Failed",
        description: "Please enter medicine details manually",
        variant: "destructive",
      })
    } finally {
      setIsProcessingOCR(false)
    }
  }

  const removeImage = (index: number) => {
    setImages((prev) => prev.filter((_, i) => i !== index))
  }

  const handleSubmit = async (e: React.FormEvent) => {
    e.preventDefault()
    setIsSubmitting(true)

    try {
      if (!db) {
        toast({
          title: "Error",
          description: "Database not initialized. Please try again.",
          variant: "destructive",
        })
        setIsSubmitting(false)
        return
      }

      if (
        !formData.medicineName ||
        !formData.brand ||
        !formData.dosage ||
        !formData.quantity ||
        !formData.expiryDate ||
        !formData.condition ||
        !formData.category
      ) {
        toast({
          title: "Missing Information",
          description: "Please fill in all required medicine fields",
          variant: "destructive",
        })
        setIsSubmitting(false)
        return
      }

      if (!formData.donorName || !formData.donorEmail || !formData.donorPhone || !formData.donorAddress) {
        toast({
          title: "Missing Information",
          description: "Please fill in all required donor information",
          variant: "destructive",
        })
        setIsSubmitting(false)
        return
      }

      const expiryDate = new Date(formData.expiryDate)
      const sixMonthsFromNow = new Date()
      sixMonthsFromNow.setMonth(sixMonthsFromNow.getMonth() + 6)
      if (expiryDate < sixMonthsFromNow) {
        toast({
          title: "Invalid Expiry Date",
          description: "Medicine must have at least 6 months before expiry",
          variant: "destructive",
        })
        setIsSubmitting(false)
        return
      }

      let imageUrls: string[] = []
      if (images.length > 0) {
        imageUrls = await db.uploadMultipleImages(images, "donations")
      }

      const result = await db.submitDonation(
        {
          medicineName: formData.medicineName,
          brand: formData.brand,
          genericName: formData.genericName || undefined,
          dosage: formData.dosage,
          quantity: Number.parseInt(formData.quantity),
          expiryDate: formData.expiryDate,
          condition: formData.condition,
          category: formData.category,
          donorName: formData.donorName,
          donorEmail: formData.donorEmail,
          donorPhone: formData.donorPhone,
          donorAddress: formData.donorAddress,
          notes: formData.notes || undefined,
        },
        imageUrls,
      )

      if (result.success) {
        toast({
          title: "Donation Submitted!",
          description: result.message,
        })
        setFormData({
          medicineName: "",
          brand: "",
          genericName: "",
          dosage: "",
          quantity: "",
          expiryDate: "",
          condition: "unopened",
          category: "tablet",
          donorName: "",
          donorEmail: "",
          donorPhone: "",
          donorAddress: "",
          notes: "",
        })
        setImages([])
      } else {
        throw new Error(result.error || result.message)
      }
    } catch (error: any) {
      toast({
        title: "Submission Failed",
        description: error.message || "Please try again later",
        variant: "destructive",
      })
    } finally {
      setIsSubmitting(false)
    }
  }

  return (
    <Card className="mx-auto max-w-2xl transition-smooth hover-lift">
      <CardHeader className="space-y-2">
        <div className="flex items-center gap-2">
          <Heart className="h-6 w-6 text-emerald-600" />
          <CardTitle className="text-2xl">Donate Medicines</CardTitle>
        </div>
        <CardDescription className="text-base">
          Upload photos and our AI will automatically extract medicine details. Help us reduce medical waste and make
          healthcare accessible!
        </CardDescription>
      </CardHeader>
      <CardContent>
        <form onSubmit={handleSubmit} className="space-y-6">
          {/* Image Upload Section */}
          <div className="space-y-3 p-4 rounded-lg bg-emerald-50 dark:bg-emerald-950/20 border border-emerald-200 dark:border-emerald-800">
            <h3 className="text-lg font-semibold flex items-center gap-2 text-emerald-800 dark:text-emerald-200">
              <Sparkles className="h-5 w-5" />
              Medicine Photos (AI-Powered)
            </h3>
            <p className="text-sm text-emerald-700 dark:text-emerald-300">
              Upload clear photos of your medicine packaging. Our AI will extract details automatically!
            </p>
            <div>
              <input
                id="images"
                type="file"
                accept="image/*"
                multiple
                onChange={handleImageUpload}
                className="hidden"
                disabled={isProcessingOCR}
              />
              <Button
                type="button"
                variant="outline"
                onClick={() => document.getElementById("images")?.click()}
                className="w-full border-emerald-300 dark:border-emerald-700 hover:bg-emerald-100 dark:hover:bg-emerald-900"
                disabled={isProcessingOCR}
              >
                {isProcessingOCR ? (
                  <>
                    <Loader2 className="mr-2 h-4 w-4 animate-spin" />
                    AI Processing...
                  </>
                ) : (
                  <>
                    <Upload className="mr-2 h-4 w-4" />
                    Select Images (Max 5)
                  </>
                )}
              </Button>
            </div>
            {images.length > 0 && (
              <div className="mt-4 grid grid-cols-2 md:grid-cols-3 gap-4">
                {images.map((image, index) => (
                  <div key={index} className="relative group">
                    <img
                      src={URL.createObjectURL(image) || "/placeholder.svg"}
                      alt={`Medicine ${index + 1}`}
                      className="h-24 w-full object-cover rounded-md border-2 border-emerald-200 dark:border-emerald-700"
                    />
                    <Button
                      type="button"
                      variant="destructive"
                      size="sm"
                      className="absolute -top-2 -right-2 h-6 w-6 rounded-full p-0 opacity-0 group-hover:opacity-100 transition-opacity"
                      onClick={() => removeImage(index)}
                    >
                      <X className="h-3 w-3" />
                    </Button>
                  </div>
                ))}
              </div>
            )}
          </div>

          {/* Medicine Information */}
          <div className="space-y-4">
            <h3 className="text-lg font-semibold text-slate-800 dark:text-slate-200">Medicine Information</h3>
            <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
              <div className="space-y-2">
                <Label htmlFor="medicineName">Medicine Name *</Label>
                <Input
                  id="medicineName"
                  name="medicineName"
                  value={formData.medicineName}
                  onChange={handleInputChange}
                  placeholder="e.g., Paracetamol"
                  className="transition-smooth focus:ring-2 focus:ring-emerald-500"
                  required
                />
              </div>
              <div className="space-y-2">
                <Label htmlFor="brand">Brand *</Label>
                <Input
                  id="brand"
                  name="brand"
                  value={formData.brand}
                  onChange={handleInputChange}
                  placeholder="e.g., Crocin"
                  className="transition-smooth focus:ring-2 focus:ring-emerald-500"
                  required
                />
              </div>
            </div>

            <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
              <div className="space-y-2">
                <Label htmlFor="dosage">Dosage *</Label>
                <Input
                  id="dosage"
                  name="dosage"
                  value={formData.dosage}
                  onChange={handleInputChange}
                  placeholder="e.g., 500mg"
                  className="transition-smooth focus:ring-2 focus:ring-emerald-500"
                  required
                />
              </div>
              <div className="space-y-2">
                <Label htmlFor="quantity">Quantity *</Label>
                <Input
                  id="quantity"
                  name="quantity"
                  type="number"
                  min="1"
                  value={formData.quantity}
                  onChange={handleInputChange}
                  placeholder="Number of tablets/bottles"
                  className="transition-smooth focus:ring-2 focus:ring-emerald-500"
                  required
                />
              </div>
            </div>

            <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
              <div className="space-y-2">
                <Label htmlFor="expiryDate">Expiry Date *</Label>
                <Input
                  id="expiryDate"
                  name="expiryDate"
                  type="date"
                  value={formData.expiryDate}
                  onChange={handleInputChange}
                  className="transition-smooth focus:ring-2 focus:ring-emerald-500"
                  required
                />
              </div>
              <div className="space-y-2">
                <Label htmlFor="category">Category *</Label>
                <select
                  id="category"
                  name="category"
                  value={formData.category}
                  onChange={handleInputChange}
                  className="w-full h-10 px-3 rounded-md border border-slate-300 dark:border-slate-700 bg-white dark:bg-slate-950 transition-smooth focus:ring-2 focus:ring-emerald-500"
                  required
                >
                  <option value="tablet">Tablet</option>
                  <option value="capsule">Capsule</option>
                  <option value="syrup">Syrup</option>
                  <option value="injection">Injection</option>
                  <option value="cream">Cream/Ointment</option>
                  <option value="other">Other</option>
                </select>
              </div>
            </div>

            <div className="space-y-2">
              <Label htmlFor="condition">Condition *</Label>
              <select
                id="condition"
                name="condition"
                value={formData.condition}
                onChange={handleInputChange}
                className="w-full h-10 px-3 rounded-md border border-slate-300 dark:border-slate-700 bg-white dark:bg-slate-950 transition-smooth focus:ring-2 focus:ring-emerald-500"
                required
              >
                <option value="unopened">Unopened/Sealed</option>
                <option value="opened">Opened but unused</option>
                <option value="partial">Partially used</option>
              </select>
            </div>

            <div className="space-y-2">
              <Label htmlFor="notes">Additional Notes</Label>
              <Textarea
                id="notes"
                name="notes"
                value={formData.notes}
                onChange={handleInputChange}
                placeholder="Any additional information about the medicine"
                rows={3}
                className="transition-smooth focus:ring-2 focus:ring-emerald-500"
              />
            </div>
          </div>

          {/* Donor Information */}
          <div className="space-y-4">
            <h3 className="text-lg font-semibold text-slate-800 dark:text-slate-200">Your Information</h3>

            <div className="space-y-2">
              <Label htmlFor="donorName">Full Name *</Label>
              <Input
                id="donorName"
                name="donorName"
                value={formData.donorName}
                onChange={handleInputChange}
                placeholder="Your full name"
                className="transition-smooth focus:ring-2 focus:ring-emerald-500"
                required
              />
            </div>

            <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
              <div className="space-y-2">
                <Label htmlFor="donorEmail">Email *</Label>
                <Input
                  id="donorEmail"
                  name="donorEmail"
                  type="email"
                  value={formData.donorEmail}
                  onChange={handleInputChange}
                  placeholder="your.email@example.com"
                  className="transition-smooth focus:ring-2 focus:ring-emerald-500"
                  required
                />
              </div>
              <div className="space-y-2">
                <Label htmlFor="donorPhone">Phone *</Label>
                <Input
                  id="donorPhone"
                  name="donorPhone"
                  type="tel"
                  value={formData.donorPhone}
                  onChange={handleInputChange}
                  placeholder="+91 98765 43210"
                  className="transition-smooth focus:ring-2 focus:ring-emerald-500"
                  required
                />
              </div>
            </div>

            <div className="space-y-2">
              <Label htmlFor="donorAddress">Pickup Address *</Label>
              <Textarea
                id="donorAddress"
                name="donorAddress"
                value={formData.donorAddress}
                onChange={handleInputChange}
                placeholder="Complete address where we can collect the medicines"
                rows={3}
                className="transition-smooth focus:ring-2 focus:ring-emerald-500"
                required
              />
            </div>
          </div>

          <Button
            type="submit"
            className="w-full bg-emerald-600 hover:bg-emerald-700 text-white transition-smooth"
            disabled={isSubmitting || images.length === 0}
          >
            {isSubmitting ? (
              <>
                <Loader2 className="mr-2 h-4 w-4 animate-spin" />
                Submitting...
              </>
            ) : (
              <>
                <Heart className="mr-2 h-4 w-4" />
                Submit Donation
              </>
            )}
          </Button>

          <p className="text-xs text-center text-slate-500 dark:text-slate-400">
            By submitting, you agree to our terms of service and privacy policy.
          </p>
        </form>
      </CardContent>
    </Card>
  )
}

