                <div className="flex flex-col sm:flex-row gap-3">
                  <Button asChild variant="outline">
                    <Link href="/donate">Donate Medicine</Link>
                  </Button>
                  <Button asChild className="bg-emerald-600 hover:bg-emerald-700">
