    try {
      const db = await getDb()
      const { doc, getDoc } = await import("firebase/firestore")
      const docSnap = await getDoc(doc(db, "profiles", userId))

      if (!docSnap.exists()) return null

      return {
        id: docSnap.id,
        ...docSnap.data(),
