"use client"

import { useState, useEffect } from "react"
import { useAuth } from "./useAuth"

interface Notification {
  id: string
  title: string
  message: string
  type: "donation" | "volunteer" | "system" | "recall" | "achievement"
  read: boolean
  actionUrl?: string
  createdAt: string
}

export function useNotifications() {
  const { user } = useAuth()
  const [notifications, setNotifications] = useState<Notification[]>([])
  const [unreadCount, setUnreadCount] = useState(0)
  const [isLoading, setIsLoading] = useState(true)

  const fetchNotifications = async () => {
    if (!user) return

    try {
      const response = await fetch("/api/notifications")
      if (response.ok) {
        const data = await response.json()
        setNotifications(data.notifications)
        setUnreadCount(data.unreadCount)
      }
    } catch (error) {
      console.error("Error fetching notifications:", error)
    } finally {
      setIsLoading(false)
    }
  }

  const markAsRead = async (notificationId: string) => {
    try {
      const response = await fetch(`/api/notifications/${notificationId}`, {
        method: "PATCH",
        headers: { "Content-Type": "application/json" },
        body: JSON.stringify({ read: true }),
      })

      if (response.ok) {
        setNotifications((prev) => prev.map((n) => (n.id === notificationId ? { ...n, read: true } : n)))
        setUnreadCount((prev) => Math.max(0, prev - 1))
      }
    } catch (error) {
      console.error("Error marking notification as read:", error)
    }
  }

  const markAllAsRead = async () => {
    try {
      const response = await fetch("/api/notifications/mark-all-read", {
        method: "POST",
      })

      if (response.ok) {
        setNotifications((prev) => prev.map((n) => ({ ...n, read: true })))
        setUnreadCount(0)
      }
    } catch (error) {
      console.error("Error marking all notifications as read:", error)
    }
  }

  useEffect(() => {
    fetchNotifications()
  }, [user])

  // Poll for new notifications every 30 seconds
  useEffect(() => {
    if (!user) return

    const interval = setInterval(fetchNotifications, 30000)
    return () => clearInterval(interval)
  }, [user])

  return {
    notifications,
    unreadCount,
    isLoading,
    markAsRead,
    markAllAsRead,
    refetch: fetchNotifications,
  }
}

export interface OfflineData {
  id: string
  type: "donation" | "volunteer"
  data: any
  createdAt: number
}

class OfflineStorage {
  private dbName = "vitamend-offline"
  private dbVersion = 1
  private storeName = "pending-submissions"

  async openDatabase(): Promise<IDBDatabase> {
    return new Promise((resolve, reject) => {
      const request = indexedDB.open(this.dbName, this.dbVersion)

      request.onerror = () => reject(request.error)
      request.onsuccess = () => resolve(request.result)

      request.onupgradeneeded = (event) => {
        const db = (event.target as IDBOpenDBRequest).result
        if (!db.objectStoreNames.contains(this.storeName)) {
          db.createObjectStore(this.storeName, { keyPath: "id" })
        }
      }
    })
  }

  async saveDonation(data: any): Promise<string> {
    const id = crypto.randomUUID()
    const offlineData: OfflineData = {
      id,
      type: "donation",
      data,
      createdAt: Date.now(),
    }

    const db = await this.openDatabase()
    return new Promise((resolve, reject) => {
      const transaction = db.transaction(this.storeName, "readwrite")
      const store = transaction.objectStore(this.storeName)
      const request = store.add(offlineData)

      request.onerror = () => reject(request.error)
      request.onsuccess = () => {
        // Register for sync when online
        if ("serviceWorker" in navigator && "SyncManager" in window) {
          navigator.serviceWorker.ready.then((registration) => {
            registration.sync.register("donation-sync").catch((err) => {
              console.error("Background sync registration failed:", err)
            })
          })
        }
        resolve(id)
      }

      transaction.oncomplete = () => db.close()
    })
  }

  async saveVolunteer(data: any): Promise<string> {
    const id = crypto.randomUUID()
    const offlineData: OfflineData = {
      id,
      type: "volunteer",
      data,
      createdAt: Date.now(),
    }

    const db = await this.openDatabase()
    return new Promise((resolve, reject) => {
      const transaction = db.transaction(this.storeName, "readwrite")
      const store = transaction.objectStore(this.storeName)
      const request = store.add(offlineData)

      request.onerror = () => reject(request.error)
      request.onsuccess = () => {
        // Register for sync when online
        if ("serviceWorker" in navigator && "SyncManager" in window) {
          navigator.serviceWorker.ready.then((registration) => {
            registration.sync.register("volunteer-sync").catch((err) => {
              console.error("Background sync registration failed:", err)
            })
          })
        }
        resolve(id)
      }

      transaction.oncomplete = () => db.close()
    })
  }

  async getPendingSubmissions(): Promise<OfflineData[]> {
    const db = await this.openDatabase()
    return new Promise((resolve, reject) => {
      const transaction = db.transaction(this.storeName, "readonly")
      const store = transaction.objectStore(this.storeName)
      const request = store.getAll()

      request.onerror = () => reject(request.error)
      request.onsuccess = () => resolve(request.result)

      transaction.oncomplete = () => db.close()
    })
  }

  async removeSubmission(id: string): Promise<void> {
    const db = await this.openDatabase()
    return new Promise((resolve, reject) => {
      const transaction = db.transaction(this.storeName, "readwrite")
      const store = transaction.objectStore(this.storeName)
      const request = store.delete(id)

      request.onerror = () => reject(request.error)
      request.onsuccess = () => resolve()

      transaction.oncomplete = () => db.close()
    })
  }
}

export const offlineStorage = new OfflineStorage()

interface QueueJob {
  id: string
  type: string
  data: any
  attempts: number
  maxAttempts: number
  createdAt: Date
  processAt: Date
}

class SimpleQueue {
  private jobs: Map<string, QueueJob> = new Map()
  private processors: Map<string, (data: any) => Promise<void>> = new Map()
  private isProcessing = false

  addJob(type: string, data: any, delay = 0): string {
    const id = crypto.randomUUID()
    const job: QueueJob = {
      id,
      type,
      data,
      attempts: 0,
      maxAttempts: 3,
      createdAt: new Date(),
      processAt: new Date(Date.now() + delay),
    }

    this.jobs.set(id, job)
    this.processJobs()
    return id
  }

  registerProcessor(type: string, processor: (data: any) => Promise<void>) {
    this.processors.set(type, processor)
  }

  private async processJobs() {
    if (this.isProcessing) return
    this.isProcessing = true

    const now = new Date()
    const readyJobs = Array.from(this.jobs.values()).filter((job) => job.processAt <= now)

    for (const job of readyJobs) {
      try {
        const processor = this.processors.get(job.type)
        if (processor) {
          await processor(job.data)
          this.jobs.delete(job.id)
        }
      } catch (error) {
        job.attempts++
        if (job.attempts >= job.maxAttempts) {
          console.error(`Job ${job.id} failed after ${job.maxAttempts} attempts:`, error)
          this.jobs.delete(job.id)
        } else {
          job.processAt = new Date(Date.now() + Math.pow(2, job.attempts) * 1000) // Exponential backoff
        }
      }
    }

    this.isProcessing = false

    // Schedule next processing
    if (this.jobs.size > 0) {
      setTimeout(() => this.processJobs(), 5000)
    }
  }
}

